#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
namespace MF
{
	const int N=1e6+10,M=4e6+10,INF=0x3f3f3f3f;
	int head[N],des[M],nxt[M],cgt,S,s,t,que[N],H,T,dep[N],cap[M]; 
	inline void Init(){memset(head,0,(S+2)<<2);S=0;cgt=1;}
	inline void ins(const int &x,const int &y,const int &c)
	{
		nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;
		nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
	}
	inline bool bfs()
	{
		memset(dep,0,(S+2)<<2);dep[que[H=T=0]=s]=1;
		while(H<=T){int u=que[H++];grep(u,i)if(cap[i]){int v=des[i];if(!dep[v])dep[que[++T]=v]=dep[u]+1;}}
		return dep[t];
	}
	inline int dfs(const int &u=s,int in=INF)
	{
		if(u==t)return in;int out=0;
		grep(u,i)if(cap[i]&&dep[des[i]]==dep[u]+1)
		{
			int tmp=dfs(des[i],cap[i]<in?cap[i]:in);
			cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
		}
		return out?out:dep[u]=0;
	}
	inline int dinic(const int &u=1,const int &v=2){s=u;t=v;int res=0;while(bfs())res+=dfs();return res;}
}
using MF::ins;using MF::dinic;using MF::Init;using MF::S;using MF::cap;
const int N=25;int n,m,x[N],y[N],ccc;
inline void Solve()
{
	Init();n=read();m=read(); printf("Matrix %d\n",++ccc);
	rep(1,n,i)x[i]=read();drep(n,2,i)x[i]-=x[i-1];rep(1,m,i)y[i]=read();drep(m,2,i)y[i]-=y[i-1];
	rep(1,n,i)rep(1,m,j)ins(i,j+n,19); int s=0,t=S=n+m+1; rep(1,n,i)ins(s,i,x[i]-m);rep(1,m,i)ins(i+n,t,y[i]-n);
	dinic(s,t);int cur=3;rep(1,n,i){rep(1,m,j){printf("%d ",MF::cap[cur]+1);cur+=2;}putchar('\n');}putchar('\n');
}
int main(){int T=read();while(T--)Solve();}
